import json
import enum

class MyEnum(enum.Enum):
    VALUE1 = "first"
    VALUE2 = "second"
    VALUE3 = 3

class EnumEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, enum.Enum):
            return obj.value
        return json.JSONEncoder.default(self, obj)

if __name__ == '__main__':
    data = {
        "status": MyEnum.VALUE1,
        "type": MyEnum.VALUE3,
        "items": [
            {"id": 1, "enum_item": MyEnum.VALUE2},
            {"id": 2, "enum_item": MyEnum.VALUE1}
        ],
        "message": "This is a test."
    }

    serialized_data = json.dumps(data, cls=EnumEncoder, indent=4)
    print(serialized_data)

    # Örnek bir enum değerini doğrudan serialize etme
    print("\nDoğrudan bir enum değeri:", json.dumps(MyEnum.VALUE2, cls=EnumEncoder))
